import React from 'react';
import { Link } from 'react-router-dom';
import './BlogPreview.css';

const posts = [
  {
    slug: 'visual-identity',
    title: 'How to build a visual identity that stands out',
    date: 'Mar 20, 2025',
    tag: 'Branding',
    img: 'https://framerusercontent.com/images/2pZn1ac5q54fkkThIF56Vfou8.jpg',
  },
  {
    slug: 'digital-world',
    title: 'How to stay relevant in a fast-changing digital world',
    date: 'Mar 13, 2025',
    tag: 'Strategy',
    img: 'https://framerusercontent.com/images/xAmaN93UEGZxWaE2SAlY2hCRj08.jpeg',
  },
  {
    slug: 'design-trends',
    title: 'Top design trends that are reshaping the industry in 2025',
    date: 'Mar 06, 2025',
    tag: 'Design',
    img: 'https://framerusercontent.com/images/LG47yzJKYPaE9iSMjClLZQLV0Iw.jpg',
  },
];

export default function BlogPreview() {
  return (
    <section className="blog-preview">
      <div className="container">
        <div className="blog-header">
          <div>
            <p className="section-label">News & Insights</p>
            <h2 className="blog-heading">Stay ahead in the digital world.</h2>
          </div>
          <Link to="/blog" className="arrow-link">View all →</Link>
        </div>

        <div className="blog-grid">
          {posts.map((post) => (
            <Link to="/blog" key={post.slug} className="blog-card">
              <div className="blog-card-img">
                <img src={post.img} alt={post.title} />
              </div>
              <div className="blog-card-body">
                <div className="blog-card-meta">
                  <span className="blog-tag">{post.tag}</span>
                  <span className="blog-date">{post.date}</span>
                </div>
                <h3 className="blog-card-title">{post.title}</h3>
                <span className="read-link">Read article →</span>
              </div>
            </Link>
          ))}
        </div>
      </div>
    </section>
  );
}
